let allArticles = "";

for (const item of $input.all()) {

  item.json.myNewField = 1;

  let article = `<h1>${item.json.title}</h1><br>
  <p>${item.json.content}</p><br>`;

  allArticles += article;
}

// Return as an array of items (VERY IMPORTANT)
return [
  {
    json: {
      allArticles: allArticles
    }
  }
];
